mapper.select:
SELECT t.tag_id, t.tag_code, t.tag_name, t.tag_category, t.description, t.enabled, COUNT(DISTINCT r.fund_id) AS fund_count FROM fund_tag t LEFT JOIN fund_tag_relation r ON r.tag_id = t.tag_id
AND t.enabled = #{query.enabled}
AND t.tag_category = #{query.category}
AND ( t.tag_name LIKE CONCAT('%', #{query.keyword}, '%') OR t.tag_code LIKE CONCAT('%', #{query.keyword}, '%') )
GROUP BY t.tag_id, t.tag_code, t.tag_name, t.tag_category, t.description, t.enabled ORDER BY t.tag_category, t.tag_id
